#![no_std]

#![allow(non_camel_case_types)]
#![allow(non_snake_case)]
#![allow(unused_parens)]

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

// The GUMBOX contract functions (pre/post conditions) for each thread are
// originally generated into the thread's own crate. However, thread crates
// are built as staticlib for seL4/Microkit deployment, which means they
// cannot be used as Rust crate dependencies — doing so causes duplicate
// #[panic_handler] errors and crate-type conflicts with cargo-verus.
//
// This crate extracts the pure contract logic into a standalone rlib so
// that the monitor (and any other crate) can call the GUMBOX functions
// without depending on the full thread crate.
//
// All thread GUMBOX functions will be moved here so that monitors can
// evaluate pre/post conditions for every thread in the system.

pub mod thermostat_rt_mhs_mhs_GUMBOX;
